export interface GitCommitNode {
  hash: string;
  shortHash: string;
  message: string;
  author: string;
  date: number;
  branch: string;
  parents: string[];
  isMerge: boolean;
}

export interface GitBranchInfo {
  name: string;
  color: string;
  headHash: string;
}

interface GitGraphProps {
