            onCommit={handleCommit}
            fileTree={files}
          />
        ) : (
          <MemoizedHistoryTab
            commits={commits}
            expandedHash={expandedHash}
            onToggleExpand={handleToggleExpand}
            onRestore={handleRestore}
          />
        )}
      </div>
    </div>
  );
