        )}
        {tab === "pipeline" && (
          <>
            <Row label="Pass Threshold"><NumberInput value={settings.pipelinePassThreshold} onChange={(v) => update("pipelinePassThreshold", v)} min={0} max={100} /></Row>
            <p className="pt-2 text-[10px] text-text-tertiary">
