      maxTokens: 200,
      onChunk: (text: string) => {
        result += text;
      },
    });

    const summaryMatch = result.match(/SUMMARY:\s*(.+)/);
    const suggestionMatch = result.match(/SUGGESTION:\s*(.+)/);
    const fixCommandMatch = result.match(/FIX_COMMAND:\s*(.+)/);

    if (summaryMatch || suggestionMatch || fixCommandMatch) {
      return {
        summary: summaryMatch?.[1]?.trim() ?? t('terminalPanel.analysisComplete'),
        suggestion: suggestionMatch?.[1]?.trim() ?? t('terminalPanel.stderrLogs'),
        fixCommand: fixCommandMatch?.[1]?.trim(),
      };
    }
    return null;
  } catch {
    return null;
  }
}

// IDENTITY_SEAL: PART-3 | role=AI error analysis | inputs=command,stderr,exitCode | outputs=analysis|null

// ============================================================
// PART 4 — Component
// ============================================================

export function TerminalPanel({
  files = [],
  onRunPipeline,
  onAskAI,
}: TerminalPanelProps) {
  const { lang } = useLang();
  const t = createT(lang as AppLanguage);
  const [lines, setLines] = useState<TermLine[]>([]);
  const [input, setInput] = useState("");
  const [history, setHistory] = useState<string[]>([]);
  const [historyIdx, setHistoryIdx] = useState(-1);
  const [_inputHighlight, setInputHighlight] = useState<HighlightedSpan[]>([]);
  const [wcInstance, setWcInstance] = useState<WebContainerInstance | null>(null);
  const [wcBooting, setWcBooting] = useState(false);
  const [scrollLock, setScrollLock] = useState(false);
  const [autocompleteOptions, setAutocompleteOptions] = useState<string[]>([]);
  const [autocompleteIdx, setAutocompleteIdx] = useState(-1);
  const [cwd, setCwd] = useState("~/project");
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleCopyOutput = useCallback(() => {
    const text = lines.map((l) => l.text).join("\n");
    navigator.clipboard.writeText(text).then(() => {
      setLines((prev) => [
        ...prev,
        { text: t('terminalPanel.copiedToClipboard'), color: "blue" },
      ]);
    });
  }, [lines, lang]);

  // Boot WebContainer on mount
  useEffect(() => {
    let cancelled = false;
    setWcBooting(true);
    setLines([{ text: t('terminalPanel.booting'), color: "blue" }]);

    (async () => {
      try {
        const instance = await createWebContainer();
        if (cancelled) return;
        setWcInstance(instance);
        setLines([
          {
            text: instance.isAvailable
              ? "EH Code Studio Terminal v2.0 \u2014 WebContainer Ready"
              : t('terminalPanel.simulatedMode'),
            color: "green",
          },
          {
            text: instance.isAvailable
              ? t('terminalPanel.actualCommands')
              : t('terminalPanel.simulatedFallback'),
            color: instance.isAvailable ? "green" : "yellow",
          },
          { text: "" },
        ]);
      } catch (err) {
        if (cancelled) return;
        setLines([
          { text: "EH Code Studio Terminal v2.0", color: "green" },
          {
            text: `${t('terminalPanel.bootFailed')}: ${(err as Error).message}`,
            color: "red",
          },
          {
            text: t('terminalPanel.fallbackToBuiltin'),
            color: "yellow",
          },
          { text: "" },
        ]);
      } finally {
        if (!cancelled) setWcBooting(false);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Auto-scroll
  useEffect(() => {
    if (!scrollLock) {
      scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight });
    }
  }, [lines, scrollLock]);

  // Highlight input on change
  useEffect(() => {
    setInputHighlight(highlightInput(input, shellEnv));
  }, [input]);

  // IDENTITY_SEAL: PART-4 | role=component state+effects | inputs=Props | outputs=React state

  // ============================================================
  // PART 5 — Command Handler
  // ============================================================

  const resetInput = useCallback((cmd: string) => {
    shellHistory.push(cmd, shellEnv.getCwd());
    setHistory((prev) => [...prev.slice(-50), cmd]);
    setHistoryIdx(-1);
    setInput("");
    setAutocompleteOptions([]);
    setAutocompleteIdx(-1);
  }, []);

  const handleCommand = useCallback(async (overrideCmd?: string | React.MouseEvent) => {
    let cmd = typeof overrideCmd === 'string' ? overrideCmd.trim() : input.trim();
    if (!cmd) return;

    const processed = preprocessCommand(cmd, shellEnv);
    if (processed.segments.length > 0 && processed.segments[0].command) {
      cmd = processed.segments
        .map((s) => [s.command, ...s.args].join(" "))
        .join(" | ");
    }

    const firstWord = cmd.split(/\s+/)[0].toLowerCase();
    if (COMMAND_ALIASES[firstWord]) {
      cmd = COMMAND_ALIASES[firstWord] + cmd.slice(firstWord.length);
    }

    if (firstWord === "clear") {
      resetInput(cmd);
      setLines([]);
      return;
    }

    if (firstWord === "aliases") {
      resetInput(cmd);
      setLines((prev) => [
        ...prev,
        { text: `$ ${cmd}`, color: "blue", isCommand: true, rawCommand: cmd },
        { text: "Command Aliases:", color: "green" },
        ...Object.entries(COMMAND_ALIASES).map(([k, v]) => ({
          text: `  ${k} \u2192 ${v}`,
          color: "yellow" as string,
        })),
        { text: "" },
      ]);
      return;
    }

    // When WebContainer is available: route local commands to emulator, rest to WC
    if (wcInstance?.isAvailable) {
      const isLocal = LOCAL_ONLY_CMDS.has(firstWord);

      if (isLocal) {
        const seg = processed.segments[0];
        if (seg) {
          const br = executeBuiltin(
            seg.command,
            seg.args,
            shellEnv,
            shellHistory,
            shellJobs,
            files,
          );
          if (br !== null) {
            resetInput(cmd);
            setLines((prev) => [
              ...prev,
              {
                text: `${shellEnv.buildPrompt()}${cmd}`,
                color: "blue",
                isCommand: true,
                rawCommand: cmd,
              },
              ...br.output.map((l) => ({ text: l.text, color: l.color })),
              { text: "" },
            ]);
            setCwd(shellEnv.getCwd());
            return;
          }
        }
      }

      resetInput(cmd);
      const cmdStart = performance.now();
      setLines((prev) => [
        ...prev,
        { text: `$ ${cmd}`, color: "blue", isCommand: true, rawCommand: cmd },
      ]);

      if (cmd.startsWith("cd ")) {
        const target = cmd.slice(3).trim();
        if (target === "..")
          setCwd((prev) => prev.split("/").slice(0, -1).join("/") || "~");
        else if (target.startsWith("/")) setCwd(target);
        else setCwd((prev) => `${prev}/${target}`);
      }

      try {
        const result = await wcInstance.run(cmd);
        const elapsed = Math.round(performance.now() - cmdStart);
        const newLines: TermLine[] = [];
        if (result.stdout)
          newLines.push({ text: result.stdout, color: "green" });
        if (result.stderr) newLines.push({ text: result.stderr, color: "red" });

        if (result.exitCode !== 0) {
          newLines.push({
            text: `Exit code: ${result.exitCode} (${elapsed}ms)`,
            color: "red",
            executionTime: elapsed,
          });
          // AI error analysis
          setLines((prev) => [...prev, ...newLines]);
          setLines((prev) => [
            ...prev,
            { text: t('terminalPanel.aiAnalysisInProgress'), color: "blue" },
          ]);
          const analysis = await analyzeErrorWithAI(
            cmd,
            result.stderr,
            result.exitCode,
            lang
          );
          if (analysis) {
            setLines((prev) => [
              ...prev,
              { text: `[AI] ${analysis.summary}`, color: "blue" },
              { text: `[AI] ${t('terminalPanel.suggestion')}: ${analysis.suggestion}`, color: "blue" },
              ...(analysis.fixCommand ? [{
                text: `💡 [${t('terminalPanel.clickToFix')}] ${analysis.fixCommand}`,
                color: "green",
                isCommand: true,
                rawCommand: analysis.fixCommand,
                isAutoHeal: true,
              } as TermLine] : []),
              { text: "" },
            ]);
          } else {
            setLines((prev) => [...prev, { text: "" }]);
          }
        } else {
          newLines.push({
            text: `Done (${elapsed}ms)`,
            color: "green",
            executionTime: elapsed,
          });
          newLines.push({ text: "" });
          setLines((prev) => [...prev, ...newLines]);
        }
      } catch (err) {
        setLines((prev) => [
          ...prev,
          { text: `Error: ${(err as Error).message}`, color: "red" },
          { text: "" },
        ]);
      }
      return;
    }

    // WC not ready or simulated: full emulation fallback
    const seg = processed.segments[0];
    if (seg) {
      const builtinResult = executeBuiltin(
        seg.command,
        seg.args,
        shellEnv,
        shellHistory,
        shellJobs,
        files,
      );
      if (builtinResult !== null) {
        resetInput(cmd);
        setLines((prev) => [
          ...prev,
          {
            text: `${shellEnv.buildPrompt()}${cmd}`,
            color: "blue",
            isCommand: true,
            rawCommand: cmd,
          },
          ...builtinResult.output.map((l) => ({ text: l.text, color: l.color })),
          { text: "" },
        ]);
        setCwd(shellEnv.getCwd());
        return;
      }
    }

    resetInput(cmd);
    const cmdStart = performance.now();
    setLines((prev) => [
      ...prev,
      { text: `$ ${cmd}`, color: "blue", isCommand: true, rawCommand: cmd },
    ]);

    if (wcInstance) {
      try {
        const result = await wcInstance.run(cmd);
        const elapsed = Math.round(performance.now() - cmdStart);
        const newLines: TermLine[] = [];
        if (result.stdout)
          newLines.push({ text: result.stdout, color: "green" });
        if (result.stderr) newLines.push({ text: result.stderr, color: "red" });
        newLines.push({
          text: `Done (${elapsed}ms)`,
          color: result.exitCode === 0 ? "green" : "red",
        });
        newLines.push({ text: "" });
        setLines((prev) => [...prev, ...newLines]);
        return;
      } catch {
        /* fall through to executeCommand */
      }
    }

    const ctx: CommandContext = {
      files,
      onRunPipeline: onRunPipeline
        ? onRunPipeline
        : (fileName) => {
            setLines((prev) => [
              ...prev,
              { text: `[CSL] Pipeline: ${fileName}`, color: "green" },
            ]);
          },
      onAskAI: onAskAI
        ? onAskAI
        : (prompt) => {
            setLines((prev) => [
              ...prev,
              { text: `[AI] ${prompt}`, color: "blue" },
            ]);
          },
    };

    const result = await executeCommand(cmd, ctx);
    const elapsed = Math.round(performance.now() - cmdStart);
    setLines((prev) => [
      ...prev,
      ...result.lines,
      { text: `Done (${elapsed}ms)`, color: "green" },
      { text: "" },
    ]);
  }, [input, files, wcInstance, onRunPipeline, onAskAI, resetInput, lang]);

  // IDENTITY_SEAL: PART-5 | role=command handler | inputs=input,files,wcInstance | outputs=terminal lines

  // ============================================================
  // PART 6 — Key Handler & Render
  // ============================================================

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "l" && (e.ctrlKey || e.metaKey)) {
      e.preventDefault();
      setLines([]);
      return;
    }

    if (e.key === "Enter") {
      if (autocompleteOptions.length > 0 && autocompleteIdx >= 0) {
        setInput(autocompleteOptions[autocompleteIdx]);
        setAutocompleteOptions([]);
        setAutocompleteIdx(-1);
      } else {
        handleCommand();
      }
    } else if (e.key === "Tab") {
      e.preventDefault();
      if (autocompleteOptions.length > 0) {
        const nextIdx = (autocompleteIdx + 1) % autocompleteOptions.length;
        setAutocompleteIdx(nextIdx);
        setInput(autocompleteOptions[nextIdx]);
      } else if (input.trim()) {
        const smart = getAutocompleteSuggestions({
          input,
          cursorPos: input.length,
          files,
          env: shellEnv,
          history: shellHistory,
        });
        if (smart.length > 0) {
          const all = smart.map((s) => s.value);
          if (all.length === 1) {
            setInput(all[0]);
          } else {
            setAutocompleteOptions(all.slice(0, 8));
            setAutocompleteIdx(0);
            setInput(all[0]);
          }
        }
      }
    } else if (e.key === "Escape") {
      setAutocompleteOptions([]);
      setAutocompleteIdx(-1);
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      if (autocompleteOptions.length > 0) {
        const next = Math.max(0, autocompleteIdx - 1);
        setAutocompleteIdx(next);
        setInput(autocompleteOptions[next]);
      } else if (history.length > 0) {
        const newIdx =
          historyIdx < 0 ? history.length - 1 : Math.max(0, historyIdx - 1);
        setHistoryIdx(newIdx);
        setInput(history[newIdx]);
      }
    } else if (e.key === "ArrowDown") {
      e.preventDefault();
      if (autocompleteOptions.length > 0) {
        const next = Math.min(
          autocompleteOptions.length - 1,
          autocompleteIdx + 1,
        );
        setAutocompleteIdx(next);
        setInput(autocompleteOptions[next]);
      } else if (historyIdx >= 0) {
        const newIdx = historyIdx + 1;
        if (newIdx >= history.length) {
          setHistoryIdx(-1);
          setInput("");
        } else {
          setHistoryIdx(newIdx);
          setInput(history[newIdx]);
        }
      }
    } else {
      if (autocompleteOptions.length > 0) {
        setAutocompleteOptions([]);
        setAutocompleteIdx(-1);
      }
    }
  };

  return (
    <div
      className="h-48 border-t border-white/8 bg-bg-primary flex flex-col"
      onClick={() => inputRef.current?.focus()}
    >
      {/* Header bar */}
      <div className="flex items-center justify-between px-3 py-1 bg-bg-secondary border-b border-white/8">
        <span className="flex items-center gap-1 text-xs text-text-secondary">
          <TerminalIcon size={12} /> {t('terminalPanel.terminal')}
          {wcInstance?.isAvailable && (
            <span className="text-[9px] px-1 py-0.5 bg-green-500/15 text-green-400 rounded">
              WebContainer
            </span>
          )}
          {wcBooting && (
            <Loader2 size={10} className="animate-spin text-blue-400" />
          )}
        </span>
        <div className="flex items-center gap-1">
          <button
            onClick={handleCopyOutput}
            className="p-0.5 hover:bg-white/5 rounded text-text-secondary hover:text-white"
            title={t('terminalPanel.copyOutput')}
            aria-label={t('terminalPanel.copyOutput')}
          >
            <Copy size={11} />
          </button>
          <button
            onClick={() => setScrollLock((v) => !v)}
            className={`p-0.5 hover:bg-white/5 rounded ${
              scrollLock
                ? "text-accent-amber"
                : "text-text-secondary hover:text-white"
            }`}
            title={scrollLock ? t('terminalPanel.autoScrollOn') : t('terminalPanel.scrollLock')}
            aria-label={scrollLock ? t('terminalPanel.autoScrollOn') : t('terminalPanel.scrollLock')}
          >
            {scrollLock ? <Lock size={11} /> : <Unlock size={11} />}
          </button>
        </div>
      </div>

      {/* Output area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-2 font-mono text-xs">
        {lines.map((line, i) => (
          <div
            key={i}
            onClick={
              line.isCommand && line.rawCommand
                ? () => {
                    if (line.isAutoHeal) {
                      setInput("");
                      inputRef.current?.focus();
                      handleCommand(line.rawCommand!);
                    } else {
                      setInput(line.rawCommand!);
                      inputRef.current?.focus();
                    }
                  }
                : undefined
            }
            style={{
              color:
                line.color === "red"
                  ? "#f85149"
                  : line.color === "green"
                    ? "#3fb950"
                    : line.color === "blue"
                      ? "#58a6ff"
                      : line.color === "yellow"
                        ? "#d29922"
                        : "#e6edf3",
              cursor: line.isCommand ? "pointer" : undefined,
              borderRadius: line.isCommand ? 2 : undefined,
            }}
            className={line.isCommand ? "hover:bg-white/5" : ""}
            title={line.isCommand ? t('terminalPanel.runAgain') : undefined}
          >
            {parseAnsi(line.text).map((span, j) => (
              <span
                key={j}
                style={{
                  color: span.color,
                  fontWeight: span.bold ? "bold" : undefined,
                  fontStyle: span.italic ? "italic" : undefined,
                  textDecoration: span.underline ? "underline" : undefined,
                  opacity: span.dim ? 0.6 : undefined,
                }}
              >
                {span.text}
              </span>
            ))}
          </div>
        ))}
      </div>

      {/* Autocomplete dropdown */}
      {autocompleteOptions.length > 1 && (
        <div className="px-2 pb-1">
          <div className="flex flex-wrap gap-1">
            {autocompleteOptions.map((opt, i) => (
              <button
                key={opt}
                onClick={() => {
                  setInput(opt);
                  setAutocompleteOptions([]);
                  setAutocompleteIdx(-1);
                  inputRef.current?.focus();
                }}
                className={`text-[9px] px-1.5 py-0.5 rounded font-mono ${
                  i === autocompleteIdx
                    ? "bg-blue-500/30 text-blue-400"
                    : "bg-white/5 text-text-secondary"
                }`}
              >
                {opt}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* CWD display */}
      <div className="px-2 text-[9px] text-text-tertiary font-mono opacity-60">
        {cwd}
      </div>

      {/* Input line */}
      <div className="flex items-center px-2 pb-2">
        <span className="text-xs text-green-400 font-mono mr-1">$</span>
        <input
          ref={inputRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          className="flex-1 bg-transparent text-xs font-mono text-green-400 outline-none placeholder:text-white/60"
          placeholder={
            wcBooting
              ? t('terminalPanel.booting')
              : t('terminalPanel.commandInput')
          }
          disabled={wcBooting}
          autoFocus
          aria-label={t('terminalPanel.commandInput')}
        />
      </div>
    </div>
  );
}

// IDENTITY_SEAL: PART-6 | role=key handler+render | inputs=user events | outputs=JSX terminal UI

// @ts-nocheck
"use client";

// ============================================================
// PART 1 — Imports & Types
// ============================================================

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Code2, Play, FolderOpen, ChevronDown, Shield, Files } from "lucide-react";
import { useLang } from "@/lib/LangContext";
import { L4 } from "@/lib/i18n";
import { TRANSLATIONS } from "@/lib/studio-translations";
import { listProjects } from "@/lib/code-studio/core/store";
import type { AppLanguage } from "@/types/i18n";
import "./welcome-screen.css";


interface WelcomeScreenProps {
  onNewFile: () => void;
  onOpenDemo: () => void;
  onBlankProject?: () => void;
  onImportProject?: () => void;
  onResumeProject?: () => void;
  onQuickVerify?: () => void;
  onOpenLocalFolder?: () => void;
  /** Desktop: `false` when file explorer closed — show left-rail hint */
  explorerOpen?: boolean;
}

// ============================================================
// PART 2 — Main WelcomeScreen
// ============================================================

export default function WelcomeScreen({
  onNewFile,
  onOpenDemo,
  onBlankProject,
  onImportProject,
  onResumeProject,
  onQuickVerify,
  onOpenLocalFolder,
  explorerOpen,
}: WelcomeScreenProps) {
  const { lang } = useLang();
  const langKey = ((lang ?? "ko").toString().toUpperCase() as AppLanguage);
  const t =
    TRANSLATIONS[langKey]?.codeStudio ??
    TRANSLATIONS.KO?.codeStudio ??
    ({
      title: "EH Code Studio",
      subtitle: "Agentic coding engine",
      loading: "Loading...",
      openDemo: "Open Demo",
      openDemoDesc: "Start with a demo project",
      resumeProject: "Resume last project",
      resumeProjectDesc: "Continue where you left off",
      newFile: "New file",
      newFileDesc: "Create an empty file and start editing",
      blankProject: "Blank project",
      importFiles: "Import files",
      explorerClosedTitle: "Explorer is closed",
      explorerClosedDesc: "In the left activity bar, tap the Files (folder) icon to open the project tree. Choose a file to open the editor in this area.",
      greetingTitle: "Hi there!",
      greetingDesc: "How can I help?",
      quickVerifyTitle: "AI Code Verify",
      quickVerifyDesc: "Paste → Verify / Generate → Verify",
      openLocalFolder: "Open Local Folder",
      openLocalFolderDesc: "Select a folder from your system",
      lessOptions: "Less",
      moreOptions: "More options",
      commandPalette: "Commands",
      terminal: "Terminal",
    } as Record<string, string>);
  const [visible, setVisible] = useState(false);
  const [hasProjects, setHasProjects] = useState(false);
  const [showExtras, setShowExtras] = useState(false);
  const isElectron =
    typeof window !== "undefined" &&
    (!!(window as { cs?: unknown }).cs || !!(window as { electron?: unknown }).electron);

  useEffect(() => {
    const t1 = setTimeout(() => setVisible(true), 100);
    return () => clearTimeout(t1);
  }, []);

  useEffect(() => {
    listProjects().then((projects) => setHasProjects(projects.length > 0)).catch(() => {});
  }, []);

  // Primary CTA selection logic
  const primaryLabel = hasProjects
    ? (t as Record<string, string>).resumeProject ?? "Resume Last Project"
    : t.openDemo;
  const primaryDesc = hasProjects
    ? (t as Record<string, string>).resumeProjectDesc ?? "Continue where you left off"
    : t.openDemoDesc;
  const primaryAction = hasProjects ? (onResumeProject ?? onOpenDemo) : onOpenDemo;
  const primaryIcon = hasProjects
    ? <FolderOpen className="h-6 w-6 text-accent-amber" />
    : <Play className="h-6 w-6 text-accent-purple" />;
  const primaryAccent = hasProjects ? "bg-accent-amber/10" : "bg-accent-purple/10";

  const showExplorerHint = explorerOpen === false;

  return (
    <div className="relative flex h-full w-full min-w-0 flex-col overflow-hidden bg-bg-primary">
      {/* Premium Background Effects */}
      <div className="pointer-events-none absolute inset-0">
        <div className="welcome-bg-glow-1 absolute left-1/2 top-1/3 h-[min(600px,100vw)] w-[min(600px,100vw)] -translate-x-1/2 -translate-y-1/2 rounded-full opacity-[0.07]" />
        <div className="welcome-bg-glow-2 absolute left-1/4 top-2/3 h-[400px] w-[400px] -translate-x-1/2 -translate-y-1/2 rounded-full opacity-[0.04]" />
        <div className="welcome-bg-glow-3 absolute right-1/4 top-1/4 h-[300px] w-[300px] -translate-x-1/2 -translate-y-1/2 rounded-full opacity-[0.03]" />
        <div className="welcome-bg-grid welcome-bg-grid-dim absolute inset-0 opacity-[0.03]" />
      </div>

      {/* Left-rail onboarding — only when explorer is closed (desktop) */}
      {showExplorerHint && (
        <div
          className="relative z-20 flex shrink-0 items-start gap-3 border-b border-border bg-bg-secondary px-4 py-3 text-left shadow-sm sm:items-center"
          role="status"
        >
          <div className="mt-0.5 flex h-9 w-9 shrink-0 items-center justify-center rounded-lg border border-border bg-bg-primary text-accent-green sm:mt-0">
            <Files className="h-4 w-4" aria-hidden />
          </div>
          <div className="min-w-0 flex-1">
            <p className="font-mono text-xs font-semibold text-text-primary">
              {t.explorerClosedTitle}
            </p>
            <p className="mt-1 font-mono text-[11px] leading-snug text-text-secondary">
              {t.explorerClosedDesc}
            </p>
          </div>
        </div>
      )}

      <div
        className={`relative z-10 flex min-h-0 flex-1 flex-col items-center gap-5 overflow-y-auto overflow-x-hidden px-4 py-8 sm:gap-6 sm:px-6 sm:py-10 transition-all duration-700 ease-out ${
          visible ? "translate-y-0 opacity-100" : "translate-y-6 opacity-0"
        } ${showExplorerHint ? "sm:py-6" : ""}`}
      >
        {/* Mascot — no side bubble; greeting sits in document flow */}
