/** Strip markdown code fences (```...```) if wrapping the output */
function stripCodeFences(code: string): string {
  const trimmed = code.trim();
  const fenceMatch = trimmed.match(/^```[\w]*\n([\s\S]*?)\n```$/);
  if (fenceMatch) return fenceMatch[1].trim();
  return trimmed;
}

